```py
#!/usr/bin/env python3
# -*- coding: utf-8 -*-

from flask import Flask, request, jsonify, session, render_template, render_template_string, redirect, url_for, make_response
import os
import json
import unicodedata
import random
import time

app = Flask(__name__)


random.seed(int(time.time()))
secret_key = ''.join(random.choices('0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ', k=32))
app.config['SECRET_KEY'] = secret_key

app.flag_content = "xxxx"


# ==================== 数据模型 ====================
class User:
    def __init__(self, username, password):
        self.username = username
        self.password = password
        self.is_admin = False
        self.balance = 1000.0

    def verify_password(self, password):
        return self.password == password


class Product:
    def __init__(self, name, price, stock, owner=None):
        self.name = name
        self.price = price
        self.stock = stock
        self.owner = owner
        self.is_flag = False


class Admin:
    def __init__(self):
        self.username = ""
        self.identity = ""


# ==================== 数据存储 ====================
users = []
products = []
admin_obj = []


def merge(src, dst):
    for k, v in src.items():
        if hasattr(dst, '__getitem__'):
            if dst.get(k) and type(v) == dict:
                merge(v, dst.get(k))
            else:
                dst[k] = v
        elif hasattr(dst, k) and type(v) == dict:
            merge(v, getattr(dst, k))
        else:
            setattr(dst, k, v)


def forbidden(body: str, forbidden=['__init__', '__globals__', '{', '}', 'і', 'а', 'е', 'о', 'р', 'с', 'х', 'у', 'І', 'А', 'Е', 'О', 'Р', 'С', 'Х', 'У','static']):
    if not isinstance(body, str):
        return True
    try:
        data = json.loads(body)

        def check_string(s):
            """检查字符串是否包含禁用词"""
            s_str = str(s).lower()

            # 直接检查禁用词（包括西里尔字母）
            for f in forbidden:
                if f in s_str:
                    return False

            return True

        def check_values(obj):
            if isinstance(obj, dict):
                for key, value in obj.items():
                    if not check_string(key):
                        return False
                    if not check_values(value):
                        return False
            elif isinstance(obj, list):
                for item in obj:
                    if not check_values(item):
                        return False
            elif isinstance(obj, str):
                if not check_string(obj):
                    return False
            return True

        return check_values(data)
    except:
        return True


# ==================== 路由 ====================
@app.route('/')
def index():
    return render_template('index.html')


@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'GET':
        return render_template('register.html')

    if request.is_json:
        data = request.get_json()
    else:
        data = request.form

    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return render_template('message.html',
                               type='error',
                               title='注册失败',
                               message='用户名和密码不能为空',
                               back_url=url_for('register'),
                               back_text='返回注册')

    for u in users:
        if u.username == username:
            if request.is_json:
                return jsonify({'error': '用户名已存在'}), 400
            return render_template('message.html',
                                   type='error',
                                   title='注册失败',
                                   message='用户名已存在',
                                   back_url=url_for('register'),
                                   back_text='返回注册')

    user = User(username=username, password=password)
    users.append(user)

    if request.is_json:
        return jsonify({'message': '注册成功', 'username': username, 'balance': user.balance}), 201

    return render_template('message.html',
                           type='success',
                           title='注册成功',
                           message=f'<p>用户名: {username}</p><p>初始余额: 1000</p>',
                           back_url=url_for('login'),
                           back_text='去登录')


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET':
        return render_template('login.html')

    if request.is_json:
        data = request.get_json()
    else:
        data = request.form

    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return render_template('message.html',
                               type='error',
                               title='登录失败',
                               message='用户名和密码不能为空',
                               back_url=url_for('login'),
                               back_text='返回登录')

    for u in users:
        if u.username == username and u.verify_password(password):
            session['username'] = username
            session['identity'] = 'admin' if u.is_admin else 'guest'

            if request.is_json:
                return jsonify({
                    'message': '登录成功',
                    'username': username,
                    'identity': session['identity'],
                    'balance': u.balance
                })

            return redirect(url_for('index'))

    if request.is_json:
        return jsonify({'error': '用户名或密码错误'}), 401

    return render_template('message.html',
                           type='error',
                           title='登录失败',
                           message='用户名或密码错误',
                           back_url=url_for('login'),
                           back_text='返回登录')


@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))


@app.route('/products')
def get_products():
    response = render_template('products.html', products=enumerate(products))
    resp = make_response(response)
    resp.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, max-age=0'
    resp.headers['Pragma'] = 'no-cache'
    resp.headers['Expires'] = '0'
    return resp


@app.route('/products/add', methods=['GET', 'POST'])
def add_product():
    username = session.get('username')
    identity = session.get('identity')
    if not username:
        return redirect(url_for('login'))
    if identity != 'admin':
        if request.method == 'GET':
            return render_template('message.html',
                                   type='error',
                                   title='访问被拒绝',
                                   message='需要管理员权限',
                                   back_url=url_for('index'),
                                   back_text='返回首页')
        if request.is_json:
            return jsonify({'error': '需要管理员权限'}), 403
        return render_template('message.html',
                               type='error',
                               title='访问被拒绝',
                               message='需要管理员权限',
                               back_url=url_for('index'),
                               back_text='返回首页')

    if request.method == 'GET':
        return render_template('add_product.html')

    if request.is_json:
        data = request.get_json()
    else:
        data = request.form

    name = data.get('name')
    price = float(data.get('price', 10.0))
    stock = int(data.get('stock', 10))

    if not name:
        return render_template('message.html',
                               type='error',
                               title='上传失败',
                               message='商品名称不能为空',
                               back_url=url_for('add_product'),
                               back_text='返回')

    product = Product(name=name, price=price, stock=stock, owner=username)
    products.append(product)

    if request.is_json:
        return jsonify({'message': '商品创建成功', 'product_id': len(products) - 1}), 201

    return redirect(url_for('get_products'))


@app.route('/products/<int:product_id>/edit', methods=['GET'])
def update_product_page(product_id):
    username = session.get('username')
    identity = session.get('identity')
    if not username:
        return redirect(url_for('login'))

    if identity != 'admin':
        return render_template('message.html',
                               type='error',
                               title='权限不足',
                               message='需要管理员权限',
                               back_url=url_for('get_products'),
                               back_text='返回商品列表')

    if product_id >= len(products):
        return render_template('message.html',
                               type='error',
                               title='错误',
                               message='商品不存在',
                               back_url=url_for('get_products'),
                               back_text='返回商品列表')

    product = products[product_id]
    return render_template('update_product.html', product_id=product_id, product=product)


@app.route('/products/<int:product_id>/update', methods=['POST'])
def update_product(product_id):
    username = session.get('username')
    if not username:
        return jsonify({'error': '请先登录'}), 401

    if session.get('identity') != 'admin':
        return jsonify({'error': '需要管理员权限'}), 403

    if product_id >= len(products):
        return jsonify({'error': '商品不存在'}), 404

    product = products[product_id]

    raw_body = request.get_data(as_text=True)
    if not forbidden(raw_body):
        return jsonify({'error': '可恶的hack,不要破坏商店'}), 400

    data = request.get_json()

    if isinstance(data, dict):
        payload_product = data.get('product') or {}
        if isinstance(payload_product, dict):
            name_val = payload_product.get('name')
            price_val = payload_product.get('price')
            stock_val = payload_product.get('stock')
            if name_val is not None and name_val != '':
                product.name = str(name_val)
            if price_val is not None:
                try:
                    product.price = float(price_val)
                except Exception:
                    pass
            if stock_val is not None:
                try:
                    product.stock = int(stock_val)
                except Exception:
                    pass

    try:
        target = {'product': product, 'app': app}
        merge(data, target)

        return jsonify({
            'message': '商品更新成功',
            'name': product.name,
            'stock': product.stock
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/products/<int:product_id>/buy', methods=['POST'])
def buy_product(product_id):
    username = session.get('username')
    if not username:
        return redirect(url_for('login'))

    if product_id >= len(products):
        return render_template('message.html',
                               type='error',
                               title='购买失败',
                               message='商品不存在',
                               back_url=url_for('get_products'),
                               back_text='返回商品列表')

    product = products[product_id]

    if product.stock <= 0:
        return render_template('message.html',
                               type='error',
                               title='购买失败',
                               message='商品库存不足',
                               back_url=url_for('get_products'),
                               back_text='返回商品列表')

    current_user = None
    for u in users:
        if u.username == username:
            current_user = u
            break

    if current_user.balance < product.price:
        return render_template('message.html',
                               type='error',
                               title='购买失败',
                               message=f'余额不足！当前余额: ¥{current_user.balance}',
                               back_url=url_for('get_products'),
                               back_text='返回商品列表')

    current_user.balance -= product.price
    product.stock -= 1

    if product.is_flag:
        try:
            flag_display = getattr(app, 'flag_content', 'xxxx')
            rendered_flag = render_template_string(
                str(flag_display),
                app=app,
                config=app.config,
                session=session,
                user=current_user,
                product=product
            )
        except Exception as e:
            rendered_flag = str(getattr(app, 'flag_content', 'xxxx'))

        return render_template('message.html',
                               type='flag',
                               title='恭喜你！',
                               message=f'<h2 style="color:#667eea;word-break:break-all;margin:20px 0;">{rendered_flag}</h2><p>你成功获得了FLAG！</p>',
                               back_url=url_for('get_products'),
                               back_text='返回商品列表')

    return render_template('message.html',
                           type='success',
                           title='购买成功',
                           message=f'剩余余额: ¥{current_user.balance}',
                           back_url=url_for('get_products'),
                           back_text='返回商品列表')


@app.route('/profile')
def profile():
    username = session.get('username')
    if not username:
        return redirect(url_for('login'))

    for u in users:
        if u.username == username:
            return render_template('profile.html', user=u)

    return redirect(url_for('login'))


@app.route('/admin')
def admin():
    username = session.get('username')
    identity = session.get('identity')

    if not username or identity != 'admin':
        return render_template('message.html',
                               type='error',
                               title='访问被拒绝',
                               message='需要管理员权限',
                               back_url=url_for('index'),
                               back_text='返回首页')

    admin = Admin()
    merge(session, admin)
    admin_obj.append(admin)

    return render_template('admin.html', products=enumerate(products), users=users)


# ==================== 初始化 ====================
def init_data():
    admin_user = User(username='admin', password='xxxxxx')#不要爆破！！！
    admin_user.is_admin = True
    admin_user.balance = 0
    users.append(admin_user)

    flag_product = Product(name='FLAG', price=1.0, stock=0)
    flag_product.is_flag = True
    products.append(flag_product)

    products.append(Product(name='iPhone', price=999, stock=10, owner='admin'))
    products.append(Product(name='MacBook', price=1999, stock=5, owner='admin'))

    print('[+] 系统初始化完成')


if __name__ == '__main__':
    init_data()
    app.run(host='0.0.0.0', port=5000, debug=False)
```

