```py
import requests
import base64
import cv2
import numpy as np
import time


URL = "http://47.98.117.93:44877/"   # ← 改成题目的域名/IP
s = requests.Session()


# -----------------------------
# Base64 清洗
# -----------------------------
def clean_b64(b64str):
    if not b64str:
        return ""

    b64str = b64str.replace("\\/", "/")
    b64str = b64str.replace("\n", "").replace("\r", "").replace(" ", "")
    if "," in b64str:
        b64str = b64str.split(",")[-1]

    pad = len(b64str) % 4
    if pad != 0:
        b64str += "=" * (4 - pad)
    return b64str


# -----------------------------
# b64 转 cv2 图像
# -----------------------------
def b64_to_img(b64data):
    b64data = clean_b64(b64data)
    raw = base64.b64decode(b64data)
    arr = np.frombuffer(raw, np.uint8)
    return cv2.imdecode(arr, cv2.IMREAD_COLOR)


# -----------------------------
# 找滑块位置（关键）
# -----------------------------
def find_x_offset(bg, slice_img, y_pos):
    # 转灰度
    bg_gray = cv2.cvtColor(bg, cv2.COLOR_BGR2GRAY)
    sl_gray = cv2.cvtColor(slice_img, cv2.COLOR_BGR2GRAY)

    # 用模板匹配（最常用的破解方式）
    res = cv2.matchTemplate(bg_gray, sl_gray, cv2.TM_CCOEFF_NORMED)

    # 最大匹配位置
    _, max_val, _, max_loc = cv2.minMaxLoc(res)

    x, y = max_loc
    print(f"[*] 模板匹配: x={x}, score={max_val:.4f}")

    return x


# -----------------------------
# 获取一张验证码并求 offset
# -----------------------------
def solve_one():
    r = s.get(URL + "/captcha")
    j = r.json()

    slice_img = b64_to_img(j["slice"])
    bg_img = b64_to_img(j["src_bg"])
    y = j["y_pos"]

    x_offset = find_x_offset(bg_img, slice_img, y)

    return x_offset


# -----------------------------
# 向服务端提交答案
# -----------------------------
def submit(x):
    r = s.post(URL + "/validate", json={"x_pos": int(x)})
    return r.json()


# -----------------------------
# 连续破解（自动 10 次）
# -----------------------------
def main():
    while True:
        print("\n=== 新一轮验证码 ===")
        x = solve_one()

        res = submit(x)
        print(res)

        if res["code"] == 0:
            print("\n🎉 已完成全部验证，可拿 flag")
            break

        time.sleep(0.5)


if __name__ == "__main__":
    main()

